import { ArrowDownCircle, ArrowUpCircle } from "lucide-react";
import type { LeaderboardEntry } from "@/lib/leaderboard";

interface LeaderboardListProps {
  entries: LeaderboardEntry[];
}

function getRankBadgeClass(rank: number): string {
  if (rank === 1) return "bg-[#22c55e] text-white";
  if (rank === 2) return "bg-[#a855f7] text-white";
  if (rank === 3) return "bg-[#6b7280] text-white";
  return "bg-[#d4d9e4] text-[#212631]";
}

function Avatar({ entry }: { entry: LeaderboardEntry }) {
  const displayName = entry.displayName ?? entry.name;
  const initials = displayName
    .split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);

  if (entry.avatarUrl) {
    return (
      <img
        src={entry.avatarUrl}
        alt=""
        className="h-10 w-10 shrink-0 rounded-full object-cover"
      />
    );
  }
  return (
    <span
      className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-[#5b6880] text-sm font-medium text-white"
      aria-hidden
    >
      {initials}
    </span>
  );
}

export function LeaderboardList({ entries }: LeaderboardListProps) {
  return (
    <div className="bg-white rounded-lg shadow-sm border border-[#d8d9db] overflow-hidden">
      <div className="bg-[#5b6880] px-6 py-4">
        <h2 className="text-white font-semibold text-lg">Full Rankings</h2>
      </div>
      <ul
        className="divide-y divide-[#d8d9db]"
        aria-label="Leaderboard by points (received and given kudos)"
      >
        {entries.map((entry, index) => {
          const rank = index + 1;
          const displayName = entry.displayName ?? entry.name;
          const roleLabel = entry.position ?? "Team Member";
          return (
            <li key={entry.id}>
              <article
                className="flex items-center justify-between gap-4 p-4 hover:bg-[#f5f6f8] transition-colors"
                aria-label={`${displayName}, ${entry.kudosReceived} received, ${entry.kudosGiven} given, ${entry.points} points`}
              >
                <div className="flex min-w-0 flex-1 items-center gap-4">
                  <span
                    className={`flex h-8 w-8 shrink-0 items-center justify-center rounded-full text-sm font-semibold ${getRankBadgeClass(rank)}`}
                    aria-hidden="true"
                  >
                    {rank}
                  </span>
                  <Avatar entry={entry} />
                  <div className="min-w-0">
                    <p className="font-medium text-[#212631]">{displayName}</p>
                    <p className="text-sm text-[#66686c]">{roleLabel}</p>
                  </div>
                </div>
                <div className="flex shrink-0 items-center gap-4 text-sm text-[#3d4657]">
                  <span className="flex items-center gap-1.5">
                    <ArrowDownCircle className="h-4 w-4 shrink-0" aria-hidden />
                    {entry.kudosReceived} Received
                  </span>
                  <span className="flex items-center gap-1.5">
                    <ArrowUpCircle className="h-4 w-4 shrink-0" aria-hidden />
                    {entry.kudosGiven} Given
                  </span>
                  <span className="font-bold text-[#212631]">
                    {entry.points} points
                  </span>
                </div>
              </article>
            </li>
          );
        })}
      </ul>
    </div>
  );
}
